const d = $input.item.json;
const content = typeof d.content_json === 'string' ? JSON.parse(d.content_json) : d.content_json;
const required = ['slug','pillar','title','description','keywords','h1','lead','eyebrow','breadcrumbLabel','about','excerpt','sections','faqs','author','publishedAt','updatedAt'];
const missing = required.filter(k => !(k in content));
if (missing.length) throw new Error('VALIDATION: Missing fields: ' + missing.join(','));
if (!Array.isArray(content.sections) || !content.sections.length) throw new Error('VALIDATION: sections vazio');
if (!/^[a-z0-9][a-z0-9-]*$/.test(content.slug)) throw new Error('VALIDATION: slug invalido');
content.updatedAt = new Date().toISOString();
delete content._raw_body;

if (Array.isArray(content.sections)) {
  content.sections = content.sections.map(section => ({
    ...section,
    blocks: Array.isArray(section.blocks) ? section.blocks.map(block => {
      if ('content' in block && !('text' in block)) {
        const { content: blockText, ...rest } = block;
        return { ...rest, text: blockText };
      }
      return block;
    }) : section.blocks
  }));
}
const tsContent = 'import type { BlogPost } from "./types";\n\nexport const post = ' + JSON.stringify(content, null, 2) + ' satisfies BlogPost;\n';
const path = 'packages/site/src/content/blog/' + content.slug + '.post.ts';
const commitMsg = 'feat(blog): publish ' + content.slug + ' (auto)\n\nPilar: ' + content.pillar + '\nDraft id: ' + d.id + '\n\nGenerated by n8n Publicador, approved by Dra. Jane Erika.';
return { json: { draft_id: d.id, queue_id: d.queue_id, slug: content.slug, title: content.title, pillar: content.pillar, file_path: path, file_content: tsContent, commit_message: commitMsg, attempt_count: d.attempt_count } };

